import React from "react";
import styled from "styled-components";
import { motion } from "framer-motion";
import { Github } from "../components/AllSvgs";

const GlassCard = styled(motion.div)`
  width: 19rem;
  min-height: 420px;
  background: linear-gradient(135deg, rgba(40,40,40,0.6), rgba(20,20,20,0.3));
  border: 1px solid rgba(255, 255, 255, 0.05);
  box-shadow: 0 15px 30px rgba(0, 0, 0, 0.6);
  border-top-left-radius: 2rem;
  border:1px solid grey;
  padding: 1.5rem;
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  backdrop-filter: blur(15px);
  transition: all 0.3s ease;
  margin: 1rem;
  text-align: center;
  z-index:-1;

  &:hover {
    transform: scale(1.05);
    border: 1px solid rgba(255, 255, 255, 0.15);
  }
`;

const CardTitle = styled.h3`
  // font-size: 1.3rem;
  // font-weight: 700;
  // padding-bottom:20px;
  // font-family: 'Inter', sans-serif;
  // color: rgba(255, 255, 255, 0.85);
  // margin-bottom: 0.6rem;
  // letter-spacing: 0.5px;
  // text-shadow: 0 1px 1px rgba(0, 0, 0, 0.04);
   font-size: 1.4rem;
  font-weight: 700;
  color: #ffffff;
  margin-bottom: 0.8rem;
  letter-spacing: 1px;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.6);
`;

const CardDesc = styled.p`
  font-size: 1rem;
  font-family: Cambria, Cochin, Georgia, Times, "Times New Roman", serif;
  font-weight: 400;
  color: white;
  cursor:pointer; 
  line-height: 1.6;
  margin-bottom: 1.5rem;
  flex-grow: 1;
`;

const TagList = styled.div`
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin: 1rem 0;
`;

const Tag = styled.span`
  // font-size: 0.8rem;
  // font-weight: 600;
  // color: #2563eb;
  // padding: 0.4rem 0.8rem;
  // user-select: none;
  // transition: all 0.2s ease;

  // &:hover {
  // // background: rgba(255, 255, 255, 0.3);
  //   transform: scale(1.05);
  // }
    font-size: 0.8rem;
  font-weight: 600;
  color: #3abff8;
  background-color: rgba(255, 255, 255, 0.05);
  padding: 0.3rem 0.7rem;
  border-radius: 6px;
  transition: all 0.2s ease;

  &:hover {
    transform: scale(1.05);
    background: rgba(255, 255, 255, 0.1);
  }
`;

const CardInfo = styled.div`
  height: 200px;
  overflow-y: scroll;
  scroll-behavior: smooth;
  scrollbar-width: thin;
  scrollbar-color: #555 #111; 
  &::-webkit-scrollbar {
    width: 8px;
  }
  &::-webkit-scrollbar-track {
    background: #111; 
  }
  &::-webkit-scrollbar-thumb {
    background-color: #555;  
    border-radius: 10px;
    border: 2px solid transparent;
    background-clip: content-box;
  }
  &::-webkit-scrollbar-thumb:hover {
    background-color: #888;    
  }
`;


const CardFooter = styled.div`
  display: flex;
  justify-content: space-between;
  align-items: center;
`;

const VisitBtn = styled.a`
//   font-size: 16px;
//   padding: 0.7em 1.3em;
//   cursor: pointer;
//   transform: perspective(200px) rotateX(15deg);
//   color: white;
//   text-decoration: none;
//   font-weight: 900;
//   border: none;
//   border-radius: 5px;
//   background:rgba(255, 255, 255, 0.1);
//   //box-shadow: rgba(63, 94, 251, 0.2) 0px 40px 29px 0px;
//   will-change: transform;
//   transition: all 0.3s;
//   border-bottom: 2px solid rgba(70, 135, 252, 1);

// &:hover {
//   transform: perspective(180px) rotateX(30deg) translateY(2px);
// }

// &:active {
//   transform: perspective(170px) rotateX(36deg) translateY(5px);
// }

  font-size: 15px;
  padding: 0.6em 1.2em;
  font-weight: bold;
  color: #fff;
  text-decoration: none;
  background: rgba(255, 255, 255, 0.08);
  border-radius: 6px;
  border-bottom: 2px solid #3abff8;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 255, 255, 0.15);
    transform: scale(1.03);
  }

  &:active {
    transform: scale(0.98);
  }
`;

const GitLink = styled.a`

//   display: grid;
//   place-items: center;
//   background: #e3edf7;
//   padding: 0.3em;
//   border-radius: 10px;
//   border: 1px solid rgba(0,0,0,0);
//   cursor: pointer;
//   transition: transform 0.5s;

// &:hover {
//   border: 1px solid rgba(0,0,0,0.1);
//   transform: translateY(-0.5em);
// }

// &:svg {
//   transition: transform 0.5s;
// }

// &:hover svg {
//   transform: scale(0.9);
//   fill: #333333;
// }

  display: grid;
  place-items: center;
  background: rgba(255, 255, 255, 0.08);
  padding: 0.4em;
  border-radius: 10px;
  cursor: pointer;
  transition: all 0.3s ease;

  &:hover {
    background: rgba(255, 255, 255, 0.15);
    transform: scale(1.05);
  }

  svg {
    fill: #fff;
    transition: fill 0.3s, transform 0.3s;
  }

  &:hover svg {
    fill: #3abff8;
    transform: scale(0.95);
  }
`;

const modernVariants = {
  hidden: {
    opacity: 0,
    y: 30,
    scale: 0.95,
  },
  visible: {
    opacity: 1,
    y: 0,
    scale: 1,
    transition: {
      type: "spring",
      stiffness: 150,
      damping: 20,
      duration: 0.6,
    },
  },
  whileHover: {
    scale: 1.03,
    rotate: 0.5,
    transition: {
      type: "spring",
      stiffness: 200,
      damping: 10,
    },
  },
};

const ModernGlassCard = ({ data }) => {
  const { name, description, tags, demo, github } = data;

  return (
    <GlassCard
      variants={modernVariants}
      initial="hidden"
      animate="visible"
      whileHover="whileHover"
      role="listitem"
      tabIndex={0}
      aria-label={`Project card for ${name}`}
    >
      <motion.div>
          <CardTitle>{name}</CardTitle>
        <CardInfo className="Card-info">
        <CardDesc>{description}</CardDesc>
        <TagList>
          {tags.map((tag, idx) => (
            <Tag key={idx}>{tag}</Tag>
          ))}
        </TagList>
        </CardInfo>
      </motion.div>
      <CardFooter>
        <VisitBtn href={demo} target="_blank" rel="noopener noreferrer">
          Visit
        </VisitBtn>
        <GitLink href={github} target="_blank" rel="noopener noreferrer">
          <Github width={28} height={28} />
        </GitLink>
      </CardFooter>
    </GlassCard>
  );
};

export default ModernGlassCard;
