import React, { useEffect, lazy, Suspense, memo } from "react";
import styled, { keyframes, ThemeProvider } from "styled-components";
import { DarkTheme } from "./Themes";
import ErrorBoundary from "../utils/ErrorBoundary";
import LogoComponent from "../subComponents/LogoComponent";
import SocialIcons from "../subComponents/SocialIcons";
import PowerButton from "../subComponents/PowerButton";
import astronaut from "../assets/Images/spaceman.png";
const ParticleComponent = lazy(() => import("../subComponents/ParticleComponent"));

const float = keyframes`
  0% { transform: translateY(-10px) }
  50% { transform: translateY(15px) translateX(15px) }
  100% { transform: translateY(-10px) }
`;
const Box = styled.div`
  position: relative;
  background: ${(props) => props.theme.body};
  width: 100%;
  min-height: 100vh;
  overflow: hidden;
  display: flex;
  flex-direction: column;
`;

const Spaceman = styled.div`
  position: absolute;
  top: 10%;
  right: 5%;
  width: 23vw;
  animation: ${float} 4s ease infinite;
  z-index: 1;

  img {
    width: 100%;
    height: auto;
    /* defer loading until needed */
    loading: lazy;
  }

  @media (max-width: 1024px) {
    width: 30vw;
    top: 8%;
    right: 3%;
  }

  @media (max-width: 768px) {
    width: 40vw;
    bottom: 10%;
    flex: right;
    transform: translateX(50%);
  }

  /* hide on very small screens to reduce clutter and improve performance */
  @media (max-width: 480px) {
    display: none;
  }
`;

// main wrapper
const MainContent = styled.div`
  display: flex;
  justify-content: flex-start;
  align-items: center;
  padding: 2rem;
  flex: 1;
  top: 50%;
  z-index: 2;
  position: relative;

  @media (max-width: 768px) {
    justify-content: center;
    padding: 1rem;
    margin-top: 4rem;
  }
`;
// fade-in animation for card entry
const fadeIn = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const GlassCard = styled.div`
  position: relative;
  max-width: 850px;
  width: 80%;               /* narrower on large screens for a more centered card */
  padding: 2.5rem 3rem;
  border-radius: 20px;
  /* blue-teal tinted glass background */
  background: rgba(0, 128, 255, 0.12);
  border: 1px solid rgba(100, 180, 220, 0.35);
  backdrop-filter: blur(16px) saturate(150%);
  -webkit-backdrop-filter: blur(16px) saturate(150%);
  box-shadow: 0 12px 48px rgba(0, 128, 255, 0.4);
  overflow: hidden;
  z-index: 2;
  animation: ${fadeIn} 1.2s ease-out both;
  transition: transform 0.3s ease;

  &:hover {
    transform: translateY(-4px);
  }

  p {
    font-size: 1.05rem;
    line-height: 1.75;
    color: #ffffff;
    margin-bottom: 1.4rem;
    text-align: justify;
  }

  &::before {
    content: "";
    position: absolute;
    inset: 0;
    background: linear-gradient(
      135deg,
      rgba(255, 255, 255, 0.35) 0%,
      rgba(255, 255, 255, 0.05) 40%,
      transparent 70%
    );
    opacity: 0.4;
    mix-blend-mode: overlay;
    pointer-events: none;
  }

  @media (max-width: 1024px) {
    width: 90%;
  }

  @media (max-width: 768px) {
    width: 95%;
    padding: 1.8rem;
  }

  @media (max-width: 480px) {
    padding: 1.2rem;
    p {
      font-size: 0.92rem;
      text-align: center;
    }
  }
`;

const SocialLinks = styled.div`
  margin-top: 1.5rem;
  ul {
    list-style: none;
    display: flex;
    gap: 1.7rem;
    flex-wrap: wrap;
    margin: 0;
    padding: 0;
    justify-content: center;
  }
  a {
    text-decoration: none;
    font-weight: 500;
    color: #ffffff;
    background: rgba(255, 255, 255, 0.1);
    border: 1px solid rgba(255, 255, 255, 0.25);
    padding: 0.5rem 1rem;
    border-radius: 12px;
    transition: all 0.3s ease;
    backdrop-filter: blur(6px);

    &:hover {
      background: rgba(255, 255, 255, 0.25);
      transform: translateY(-3px);
    }
  }
`;

// small styled component for the inner spaceman image
const SpacemanInside = styled.div`
  position: absolute;
  top: -40px;
  right: -40px;
  width: 90px;
  animation: ${float} 4s ease infinite;
  z-index: 3;

  img {
    width: 100%;
    height: auto;
    loading: lazy;
  }

  /* smaller and reposition on phones so it doesn’t obscure text */
  @media (max-width: 768px) {
    width: 60px;
    top: -30px;
    right: -30px;
  }
`;

const AboutPage = () => {
  // always display particles; they are lightweight enough for mobile
  const [showParticles, setShowParticles] = React.useState(true);
  useEffect(() => {
    import("aos").then((AOS) => {
      AOS.init({ once: true, duration: 1200 });
    });
    // no resize listener required when particles always shown
  }, []);

  return (
    <ThemeProvider theme={DarkTheme}>
      <ErrorBoundary>
        <Box>
          <LogoComponent theme="dark" />
          <SocialIcons theme="dark" />
          <PowerButton />
          {showParticles && (
            <Suspense fallback={null}>
              <ParticleComponent theme="dark" />
            </Suspense>
          )}

          {/* keep global spaceman for large-screen flair */}
          <Spaceman>
            <img src={astronaut} alt="floating astronaut" loading="lazy" />
          </Spaceman>

          <MainContent>
            <GlassCard
              data-aos="zoom-in-left"
              data-aos-duration="3000"
              data-aos-mirror="true"
            >
              {/* small spaceman inside the glass card */}
              <SpacemanInside>
                <img
                  src={astronaut}
                  alt="spaceman inside card"
                  loading="lazy"
                />
              </SpacemanInside>

              <p>
                I am a Computer Engineering student and an enthusiastic Full
                Stack Web Developer with expertise in the MERN stack (MongoDB,
                Express.js, React.js, Node.js). I enjoy building dynamic and
                user-friendly web applications, and I have practical experience
                in both frontend and backend development. Passionate about
                continuous learning, I actively explore new technologies and
                industry trends to stay updated and improve my skills. My goal
                is to design and develop modern, efficient, and impactful
                solutions that add real value.
              </p>
              <p>
                Feel free to connect with me through my social links below—I
                look forward to collaborating and growing together.
              </p>

              <SocialLinks>
                <ul>
                  <li>
                    <a
                      href="mailto:sarthakshastrakar9@gmail.com"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      E-Mail
                    </a>
                  </li>
                  <li>
                    <a
                      href="https://github.com/sarthak-shastrakar"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      GitHub
                    </a>
                  </li>
                  <li>
                    <a
                      href="http://www.linkedin.com/in/sarthak-fullstack-developer"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      LinkedIn
                    </a>
                  </li>
                  <li>
                    <a
                      href="https://www.naukri.com/mnjuser/profile"
                      target="_blank"
                      rel="noopener noreferrer"
                    >
                      Naukri
                    </a>
                  </li>
                  <li>
                    <a href="tel:+8767901968">Phone</a>
                  </li>
                </ul>
              </SocialLinks>
            </GlassCard>
          </MainContent>
        </Box>
      </ErrorBoundary>
    </ThemeProvider>
  );
};

// memoize component to prevent unnecessary re‑renders
export default memo(AboutPage);
