import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import styled from "styled-components";
import { ThemeProvider } from "styled-components";
import { DarkTheme } from "./Themes";
import PowerButton from "../subComponents/PowerButton";
import ParticleComponent from "../subComponents/ParticleComponent";
import SocialIcons from "../subComponents/SocialIcons";
import certificate1 from "../assets/Images/certificate1.jpg";
import certificate2 from "../assets/Images/certificate2.jpg";
import certificate3 from "../assets/Images/certificate3.jpg";
import certificate4 from "../assets/Images/infosys_certificate.jpg";
import certificate5 from "../assets/Images/simplilearn_certificate.jpg";
import certificate6 from "../assets/Images/simplilearn_devops.jpg";
import astronaut from "../assets/Images/spaceman.png";
import Resume from "../assets/Images/Sarthak_Fullstack_developer_new.pdf";
import "../assets/styles/certification.css";

// Simple Styled Components
const Container = styled.div`
  background: #000;
  min-height: 100vh;
  width: 100vw;
  overflow-x: hidden;
  padding: 2rem;
`;

const Spaceman = styled(motion.div)`
  position: absolute;
  top: 2%;
  right: 3%;
  width: 15vw;
  z-index: 1;

  img {
    width: 100%;
    height: auto;
  }

  @media (max-width: 480px) {
    top: 3%;
    width: 25vw;
  }
`;

const MainContent = styled(motion.div)`
  position: relative;
  z-index: 5;
  max-width: 1200px;
  margin: 0 auto;
  padding-top: 4rem;
`;

const Certificate = styled(motion.div)`
  padding-top: 2em;
  .marquee {
    margin-top: 2rem;
    overflow: scroll;
    width: 100%;
    -webkit-mask-image: linear-gradient(
      to right,
      transparent 100%,
      black 10%,
      black 90%,
      transparent 100%
    );
    mask-image: linear-gradient(
      to right,
      transparent 0%,
      black 10%,
      black 90%,
      transparent 100%
    );
  }
  .marquee_header {
    font-size: 35px;
    font-weight: 800;
    text-align: center;
    margin-bottom: 20px;
  }
  .marquee__inner {
    display: flex;
    width: max-content;
    // animation: marquee 25s linear infinite;
  }

  .marquee__group {
    display: flex;
  }

  .marquee__group span {
    margin: 0 1.5rem;
    white-space: nowrap;
    background: #000000;
    color: white;
    padding: 4px 16px 4px 12px;
    border-radius: 6px;
    font-size: 1.2rem;
  }

  @keyframes marquee {
    0% {
      transform: translateX(10);
    }
    100% {
      transform: translateX(-100%);
    }
  }
`;

const ResumeSection = styled(motion.div)`
  text-align: center;
  margin-top: 3em;

  .continue-application {
    --color: #fff;
    --background: #404660;
    --background-hover: #3a4059;
    --background-left: #2b3044;
    --folder: #f3e9cb;
    --folder-inner: #beb393;
    --paper: #ffffff;
    --paper-lines: #bbc1e1;
    --paper-behind: #e1e6f9;
    --pencil-cap: #fff;
    --pencil-top: #275efe;
    --pencil-middle: #fff;
    --pencil-bottom: #5c86ff;
    --shadow: rgba(13, 15, 25, 0.2);
    border: none;
    outline: none;
    cursor: pointer;
    position: relative;
    border-radius: 5px;
    font-size: 14px;
    font-weight: 500;
    line-height: 19px;
    -webkit-appearance: none;
    -webkit-tap-highlight-color: transparent;
    padding: 17px 29px 17px 69px;
    transition: background 0.3s;
    color: var(--color);
    background: var(--bg, var(--background));
  }

  .continue-application > div {
    top: 0;
    left: 0;
    bottom: 0;
    width: 53px;
    position: absolute;
    overflow: hidden;
    border-radius: 5px 0 0 5px;
    background: var(--background-left);
  }

  .continue-application > div .folder {
    width: 23px;
    height: 27px;
    position: absolute;
    left: 15px;
    top: 13px;
  }

  .continue-application > div .folder .top {
    left: 0;
    top: 0;
    z-index: 2;
    position: absolute;
    transform: translateX(var(--fx, 0));
    transition: transform 0.4s ease var(--fd, 0.3s);
  }

  .continue-application > div .folder .top svg {
    width: 24px;
    height: 27px;
    display: block;
    fill: var(--folder);
    transform-origin: 0 50%;
    transition: transform 0.3s ease var(--fds, 0.45s);
    transform: perspective(120px) rotateY(var(--fr, 0deg));
  }

  .continue-application > div .folder:before,
  .continue-application > div .folder:after,
  .continue-application > div .folder .paper {
    content: "";
    position: absolute;
    left: var(--l, 0);
    top: var(--t, 0);
    width: var(--w, 100%);
    height: var(--h, 100%);
    border-radius: 1px;
    background: var(--b, var(--folder-inner));
  }

  .continue-application > div .folder:before {
    box-shadow: 0 1.5px 3px var(--shadow), 0 2.5px 5px var(--shadow),
      0 3.5px 7px var(--shadow);
    transform: translateX(var(--fx, 0));
    transition: transform 0.4s ease var(--fd, 0.3s);
  }

  .continue-application > div .folder:after,
  .continue-application > div .folder .paper {
    --l: 1px;
    --t: 1px;
    --w: 21px;
    --h: 25px;
    --b: var(--paper-behind);
  }

  .continue-application > div .folder:after {
    transform: translate(var(--pbx, 0), var(--pby, 0));
    transition: transform 0.4s ease var(--pbd, 0s);
  }

  .continue-application > div .folder .paper {
    z-index: 1;
    --b: var(--paper);
  }

  .continue-application > div .folder .paper:before,
  .continue-application > div .folder .paper:after {
    content: "";
    width: var(--wp, 14px);
    height: 2px;
    border-radius: 1px;
    transform: scaleY(0.5);
    left: 3px;
    top: var(--tp, 3px);
    position: absolute;
    background: var(--paper-lines);
    box-shadow: 0 12px 0 0 var(--paper-lines), 0 24px 0 0 var(--paper-lines);
  }

  .continue-application > div .folder .paper:after {
    --tp: 6px;
    --wp: 10px;
  }

  .continue-application > div .pencil {
    height: 2px;
    width: 3px;
    border-radius: 1px 1px 0 0;
    top: 8px;
    left: 105%;
    position: absolute;
    z-index: 3;
    transform-origin: 50% 19px;
    background: var(--pencil-cap);
    transform: translateX(var(--pex, 0)) rotate(35deg);
    transition: transform 0.4s ease var(--pbd, 0s);
  }

  .continue-application > div .pencil:before,
  .continue-application > div .pencil:after {
    content: "";
    position: absolute;
    display: block;
    background: var(
      --b,
      linear-gradient(
        var(--pencil-top) 55%,
        var(--pencil-middle) 55.1%,
        var(--pencil-middle) 60%,
        var(--pencil-bottom) 60.1%
      )
    );
    width: var(--w, 5px);
    height: var(--h, 20px);
    border-radius: var(--br, 2px 2px 0 0);
    top: var(--t, 2px);
    left: var(--l, -1px);
  }

  .continue-application > div .pencil:before {
    -webkit-clip-path: polygon(0 5%, 5px 5%, 5px 17px, 50% 20px, 0 17px);
    clip-path: polygon(0 5%, 5px 5%, 5px 17px, 50% 20px, 0 17px);
  }

  .continue-application > div .pencil:after {
    --b: none;
    --w: 3px;
    --h: 6px;
    --br: 0 2px 1px 0;
    --t: 3px;
    --l: 3px;
    border-top: 1px solid var(--pencil-top);
    border-right: 1px solid var(--pencil-top);
  }

  .continue-application:before,
  .continue-application:after {
    content: "";
    position: absolute;
    width: 10px;
    height: 2px;
    border-radius: 1px;
    background: var(--color);
    transform-origin: 9px 1px;
    transform: translateX(var(--cx, 0)) scale(0.5) rotate(var(--r, -45deg));
    top: 26px;
    right: 16px;
    transition: transform 0.3s;
  }

  .continue-application:after {
    --r: 45deg;
  }

  .continue-application:hover {
    --cx: 2px;
    --bg: var(--background-hover);
    --fx: -40px;
    --fr: -60deg;
    --fd: 0.15s;
    --fds: 0s;
    --pbx: 3px;
    --pby: -3px;
    --pbd: 0.15s;
    --pex: -24px;
  }

  .continue-application a {
    text-decoration: none;
    color: white;
  }
`;

const Card = styled.div`
  margin: 0.3rem;
  .card {
    width: 300px;
    height: 300px;
    margin-left: 1rem;
    background: white;
    border-radius: 6px;
    margin-bottom: 4px;
  }

  .card-image {
    background-color: purple;
    border-radius: 6px 6px 0 0;
  }
  .card-image img {
    width: 300px;
  }
  .card-image:hover {
    transform: scale(0.98);
  }

  .category {
    text-transform: uppercase;
    font-size: 0.7em;
    font-weight: 600;
    color: rgb(63, 121, 230);
    padding: 10px 7px 0;
  }

  .category:hover {
    cursor: pointer;
  }

  .heading {
    font-weight: 600;
    color: rgb(88, 87, 87);
    padding: 7px;
    background: rgba(255, 255, 255, 0.1);
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
  }

  .author {
    color: gray;
    font-weight: 400;
    font-size: 11px;
    padding-top: 20px;
  }

  .name {
    font-weight: 600;
  }

  .name:hover {
    cursor: pointer;
  }
`;

function Certification() {
  // Animation Variants
  const containerVariants = {
    hidden: { opacity: 0 },
    visible: {
      opacity: 1,
      transition: {
        duration: 0.6,
        staggerChildren: 0.1,
      },
    },
  };

  const itemVariants = {
    hidden: { y: 50, opacity: 0 },
    visible: {
      y: 0,
      opacity: 1,
      transition: {
        duration: 0.6,
        ease: "easeOut",
      },
    },
  };

  const spacemanVariants = {
    float: {
      y: [0, -20, 0],
      x: [0, 10, 0],
      rotate: [0, 5, 0],
      transition: {
        duration: 4,
        repeat: Number.POSITIVE_INFINITY,
        ease: "easeInOut",
      },
    },
  };

  return (
    <ThemeProvider theme={DarkTheme}>
      <Container>
        {/* Animated Spaceman */}
        <Spaceman
          variants={spacemanVariants}
          animate="float"
          initial={{ opacity: 0, scale: 0 }}
          whileInView={{ opacity: 1, scale: 1 }}
          transition={{ duration: 0.8, delay: 0.5 }}
        >
          <img src={astronaut || "/placeholder.svg"} alt="spaceman" />
        </Spaceman>

        <MainContent
          variants={containerVariants}
          initial="hidden"
          animate="visible"
        >
          <SocialIcons theme="dark" />

          <PowerButton />
          <ParticleComponent theme="dark" />

          <ResumeSection
            variants={itemVariants}
            whileHover={{ scale: 1.02 }}
            className="resume-section"
          >
            <button className="continue-application">
              <div>
                <div className="pencil" />
                <div className="folder">
                  <div className="top">
                    <svg viewBox="0 0 24 27">
                      <path d="M1,0 L23,0 C23.5522847,-1.01453063e-16 24,0.44771525 24,1 L24,8.17157288 C24,8.70200585 23.7892863,9.21071368 23.4142136,9.58578644 L20.5857864,12.4142136 C20.2107137,12.7892863 20,13.2979941 20,13.8284271 L20,26 C20,26.5522847 19.5522847,27 19,27 L1,27 C0.44771525,27 6.76353751e-17,26.5522847 0,26 L0,1 C-6.76353751e-17,0.44771525 0.44771525,1.01453063e-16 1,0 Z" />
                    </svg>
                  </div>
                  <div className="paper" />
                </div>
              </div>
              <a
                href={Resume}
                target="_blank"
                rel="noopener noreferrer"
                download
              >
                Download Resume
              </a>
            </button>
          </ResumeSection>

          <Certificate
            variants={itemVariants}
            whileHover={{ scale: 1.02 }}
            className="resume-section"
          >
            <div className="marquee">
              <div className="marquee__inner">
                <div className="marquee__group">
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate1} alt="" srcset="" />
                      </div>
                      <div className="category"> Simplilearn </div>
                      <div className="heading">
                        <p>JavaScript for beginner.</p>
                        <div className="author"></div>
                      </div>
                    </div>
                  </Card>
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate2} alt="" srcset="" />
                      </div>
                      <div className="category"> Udemy </div>
                      <div className="heading">
                        <p>Full stack web development </p>
                        {/* <div className="author"></div> */}
                      </div>
                    </div>
                  </Card>
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate3} alt="" srcset="" />
                      </div>
                      <div className="category"> Great Learning </div>
                      <div className="heading">
                        {" "}
                        <p>Frontend development - css</p>
                        <div className="author"></div>
                      </div>
                    </div>
                  </Card>{" "}
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate4} alt="" srcset="" />
                      </div>
                      <div className="category"> Infosys </div>
                      <div className="heading">
                        {" "}
                        <p>Generative AI for ALL</p>
                        <div className="author"></div>
                      </div>
                    </div>
                  </Card>
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate5} alt="" srcset="" />
                      </div>
                      <div className="category"> Simplilearn </div>
                      <div className="heading">
                        {" "}
                        <p>Introduction to generative AI studio</p>
                        <div className="author"></div>
                      </div>
                    </div>
                  </Card>
                  <Card>
                    <div className="card">
                      <div className="card-image">
                        <img src={certificate6} alt="" srcset="" />
                      </div>
                      <div className="category"> Simplilearn </div>
                      <div className="heading">
                        {" "}
                        <p>Introduction to DevOps Tools</p>
                        <div className="author"></div>
                      </div>
                    </div>
                  </Card>
                </div>
              </div>
            </div>
          </Certificate>
        </MainContent>
      </Container>
    </ThemeProvider>
  );
}

export default Certification;
