import React from "react";
import styled, { keyframes, ThemeProvider } from "styled-components";
import { lightTheme } from "./Themes";
import SocialIcons from "../subComponents/SocialIcons";
import PowerButton from "../subComponents/PowerButton";
import ParticleComponent from "../subComponents/ParticleComponent";
import astronaut from "../assets/Images/astronout_3d.png";
import reactjs from "../assets/Skills/react.png";
import nodejs from "../assets/Skills/node.png";
import javascript from "../assets/Skills/JavascriptFile.png";
import html from "../assets/Skills/html.png";
import css from "../assets/Skills/css.png";
import bootstrap from "../assets/Skills/bootstrap.jpg";
import mern from "../assets/Skills/MERNlogo.png";
import Github from "../assets/Skills/githubimg.png";
import dsa from "../assets/Skills/dsa.jpg";
import Tailwind from "../assets/Skills/tailwind-css.png";
import Material from "../assets/Skills/material.jpg";
import Docker from "../assets/Skills/docker (1).png";
import Mysql from "../assets/Skills/mysql.png";
import java from "../assets/Skills/java.png";
import MongoDB from "../assets/Skills/mongo-db.png";

import { useEffect, useRef } from "react";

const Box = styled.div`
  width: 100vw;
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  position: relative;
  overflow-x: hidden;
  padding: 2rem;
  box-sizing: border-box;
`;

const float = keyframes`
  0% { transform: translateY(-10px) }
  50% { transform: translateY(15px) translateX(15px) }
  100% { transform: translateY(-10px) }
`;

const pop = keyframes`
  0% { transform: scale(1); opacity: 0.5; }
  50% { transform: scale(1.05); opacity: 1; }
  100% { transform: scale(1); opacity: 0.8; }
`;

const Spaceman = styled.div`
  position: fixed;
  top: 5%;
  right: -2%;
  width: 40vw;
  z-index: -10;
  animation: ${float} 4s ease-in-out infinite;

  img {
    width: 100%;
    height: auto;
  }

  @media (max-width: 1024px) {
    top: 4%;
    right: -10%;
    z-index: -1;
    width: 60px;
  }

  @media (max-width: 768px) {
    top: 2%;
    right: -10%;
    z-index: -1;
    width: 520px;
  }

  @media (max-width: 480px) {
    top: 10%;
    right: -10%;
    width: 400px;
    z-index: -1;
  }
`;

const SkillsGrid = styled.div`
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: 1.5rem;
  margin-top: 3rem;
  max-width: 1200px;

  @media (max-width: 480px) {
    margin-top: 6rem;
  }

  @media (max-width: 768px) {
    margin-top: 6rem;
  }
`;

const GlassWrapper = styled.div`
  backdrop-filter: blur(2px);
  background: rgba(255, 255, 255, 0.1);
  border-radius: 20px;
  padding: 1rem;
  min-width: 120px;
  max-width: 150px;
  display: flex;
  justify-content: center;
  align-items: center;
  box-shadow: 0 4px 30px rgba(0, 0, 0, 0.2);
  border: 1px solid rgba(255, 255, 255, 0.3);
  transition: transform 0.3s ease, box-shadow 0.3s ease;
  animation: ${pop} 3s ease-in-out infinite;

  &:hover {
    transform: scale(1.05);
    box-shadow: 0 6px 40px rgba(255, 255, 255, 0.3);
  }

  @media (max-width: 480px) {
    min-width: 100px;
    padding: 0.8rem;
  }
`;

const GlassInner = styled.div`
  display: flex;
  flex-direction: column;
  align-items: center;
  text-align: center;
  gap: 0.5rem;
  color: grey;

  img {
    width: 60px;
    height: auto;
    border-radius: 10%;
    object-fit: contain;
  }

  p {
    font-size: 1rem;
    margin: 0;
    font-weight: 500;
  }
`;

const MySkillsPage = () => {
  const skills = [
    { icon: reactjs, label: "React.js" },
    { icon: nodejs, label: "Node.js" },
    { icon: javascript, label: "JavaScript" },
    { icon: html, label: "HTML5" },
    { icon: css, label: "CSS3" },
    { icon: bootstrap, label: "BOOTSTRAP" },
    { icon: mern, label: "MERN" },
    { icon: java, label: "JAVA" },
    { icon: dsa, label: "DS&A" },
    { icon: Material, label: "Material UI" },
    { icon: Tailwind, label: "Tailwind CSS" },
    { icon: Github, label: "GitHub" },
    { icon: Docker, label: "Docker" },
    {icon:  Mysql , label: "MySQL" },
    {icon : MongoDB, label: "MongoDB" }
  ];

  const spacemanRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => {
      const rotation = window.scrollY * 0.15;
      if (spacemanRef.current) {
        spacemanRef.current.style.transform = `rotate(${rotation}deg)`;
      }
    };

    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  return (
    <ThemeProvider theme={lightTheme}>
      <Box>
        <SocialIcons theme="dark" />
        <ParticleComponent theme="dark" />
        <PowerButton />
        <Spaceman ref={spacemanRef}>
          <img src={astronaut} alt="spaceman" />
        </Spaceman>

        <SkillsGrid>
          {skills.map(({ icon, label }, index) => (
            <GlassWrapper key={index}>
              <GlassInner>
                <img src={icon} alt={label} />
                <p>{label}</p>
              </GlassInner>
            </GlassWrapper>
          ))}
        </SkillsGrid>
      </Box>
    </ThemeProvider>
  );
};

export default MySkillsPage;
