import React, { useEffect, useRef } from "react";
import styled, { keyframes, ThemeProvider } from "styled-components";
import { DarkTheme } from "./Themes";
import { motion } from "framer-motion";
import SocialIcons from "../subComponents/SocialIcons";
import PowerButton from "../subComponents/PowerButton";
import { Work } from "../data/WorkData";
import Card from "../subComponents/Card";
import BigTitlte from "../subComponents/BigTitlte";
import astronaut from "../assets/Images/spaceman2.png";
import ParticleComponent from "../subComponents/ParticleComponent";
// import "../assets/styles/workpage.css";

const float = keyframes`
0% { transform: translateY(-10px) }
50% { transform: translateY(15px) translateX(25px) }
100% { transform: translateY(-10px) }
`;
const Spaceman = styled.div`
  position: fixed;
  top: 9.6%;
  right: 1%;
  width: 40vw;
  animation: ${float} 4s ease infinite;
  img {
    width: 100%;
    height: auto;
  }

  @media (max-width: 480px) {
    margin-top: 1%;
    right: -20%;
    width: 90vw;
  }
`;

const Box = styled.div`
  // background-color: ${(props) => props.theme.body};
  height: 700vh;
  position: relative;
  display: flex;
  align-items: center;
`;

const Main = styled(motion.ul)`
  position: fixed;
  top: 7rem;
  height: 40vh;
  display: flex;
`;
const Rotate = styled.span`
  display: block;
  position: fixed;
  right: 1rem;
  bottom: 1rem;
  width: 80px;
  height: 80px;
  z-index: 1;
`;

const ScrollHint = styled.div`
  position: absolute;
  font-family: "Bungee Shade", cursive;
  bottom: 3rem;
  left: 50%;
  transform: translateX(-50%);
  font-size: 1rem;
  font-weight: bold;
  text-transform: uppercase;
  letter-spacing: 4px;
  color: ${(props) => props.theme.text};
  text-shadow: 0 0 8px ${(props) => props.theme.text},
    0 0 15px rgba(255, 255, 255, 0.6);
  cursor: default;
  display: flex;
  flex-direction: column;
  align-items: center;
  animation: glow 2s ease-in-out infinite alternate;

  @keyframes glow {
    from {
      opacity: 0.6;
      text-shadow: 0 0 8px ${(props) => props.theme.text};
    }
    to {
      opacity: 1;
      text-shadow: 0 0 20px ${(props) => props.theme.text},
        0 0 40px rgba(255, 255, 255, 0.8);
    }
  }

  span {
    font-size: 1rem;
    margin-top: 0.4rem;
    animation: bounce 1.5s infinite;
  }

    @media (max-width: 760px) {
    font-size:0.8rem;
  }

  @keyframes bounce {
    0%,
    100% {
      transform: translateY(0);
    }
    50% {
      transform: translateY(-8px);
    }
  }
`;

const container = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,

    transition: {
      staggerChildren: 0.5,
      duration: 0.5,
    },
  },
};

const WorkPage = () => {
  const ref = useRef(null);
  const yinyang = useRef(null);

  useEffect(() => {
    let element = ref.current;

    const rotate = () => {
      element.style.transform = `translateX(${-window.pageYOffset}px)`;

      return (yinyang.current.style.transform =
        "rotate(" + -window.pageYOffset + "deg)");
    };

    window.addEventListener("scroll", rotate);
    return () => {
      window.removeEventListener("scroll", rotate);
    };
  }, []);

  return (
    <ThemeProvider theme={DarkTheme}>
      <Box>
        <ParticleComponent theme="dark" />

        {/* <LogoComponent theme="dark"/> */}
        <SocialIcons theme="dark" />
        <PowerButton />

        <Spaceman>
          <img src={astronaut} alt="spaceman" />
        </Spaceman>

        <Main ref={ref} variants={container} initial="hidden" animate="show">
          {Work.map((d) => (
            <Card key={d.id} data={d} />
          ))}
        </Main>
        {/* <div className="card">
          <div className="content">
            {Work.map((d) => (
              <Card key={d.id} data={d} />
            ))}
          </div>
        </div> */}
        {/* <Rotate ref={yinyang}>
          <YinYang width={80} height={80} fill={DarkTheme.text} />
        </Rotate> */}

        <BigTitlte text="WORK" top="10%" left="20%" />
      </Box>
      <ScrollHint>
        Scroll Up
        <span>↑</span>
      </ScrollHint>
    </ThemeProvider>
  );
};

export default WorkPage;
