const Center = styled.button`
  position: absolute;
  top: ${p => p.click ? "85%" : "50%"};
  left: ${p => p.click ? "92%" : "50%"};
  transform: translate(-50%, -50%);
  border: none;
  outline: none;
  background: transparent;
  cursor: pointer;
  display: flex;
  flex-direction: column;
  align-items: center;
  transition: all 0.8s cubic-bezier(0.68, -0.6, 0.32, 1.6);
  z-index: 3;

  &:focus {
    outline: none;
  }

  .dragon-container {
    position: relative;
    width: ${p => p.click ? "70px" : "120px"};
    height: ${p => p.click ? "70px" : "120px"};
    border-radius: 50%;
    background: ${p => p.click ? "rgba(37, 99, 235, 0.2)" : "rgba(37, 99, 235, 0.1)"};
    display: flex;
    justify-content: center;
    align-items: center;
    border: 1.5px solid rgba(96, 165, 250, ${p => p.click ? "0.6" : "0.3"});
    transition: all 0.4s ease;
    will-change: transform;
    box-shadow: 0 0 20px rgba(96, 165, 250, 0.4); /* subtle glow */
    
    &:hover {
      transform: scale(1.05);
      box-shadow: 0 0 30px rgba(96, 165, 250, 0.6); /* stronger glow on hover */
    }

    &::before {
      content: "";
      position: absolute;
      top: -8px; left: -8px; right: -8px; bottom: -8px;
      border-radius: 50%;
      border: 1.5px solid transparent;
      border-top-color: rgba(96, 165, 250, 0.6);
      border-right-color: rgba(96, 165, 250, 0.3);
      animation: ${rotate360} ${p => p.click ? "6s" : "12s"} linear infinite; /* rotating half-circle */
    }

    img {
      width: ${p => p.click ? "56px" : "96px"};
      height: ${p => p.click ? "56px" : "96px"};
      object-fit: contain;
      animation: ${float} 4s ease-in-out infinite;
    }
  }

  span {
    display: ${p => p.click ? "none" : "inline-block"};
    padding-top: 1rem;
    font-size: 0.9rem;
    color: #60A5FA;
    letter-spacing: 1.5px;
    font-weight: 600;
    text-transform: uppercase;
    position: relative;
    text-shadow: 0 1px 2px rgba(15, 23, 46, 0.3);
  }
`;
/* Nav Pills */
const navPill = `
  .nav-text{
    color:#60A5FA;
    font-weight:600;
    font-size:0.95rem;
    padding:0.5rem 1rem;
    border-radius:8px;
    background: rgba(30,64,175,0.15);
    border:1px solid rgba(96,165,250,0.4);
    backdrop-filter:blur(6px);
    display:inline-flex;align-items:center;justify-content:center;
    transition: all 0.25s ease;
    &:hover{
      background: rgba(30,64,175,0.25);
      border-color: rgba(96,165,250,0.7);
      color:#E5E7EB;
      transform:translateY(-2px);
      box-shadow:0 4px 12px rgba(30,64,175,0.2);
    }
  }
`;

const NavLinkStyled = styled(NavLink)`
  text-decoration: none;
  z-index: 2;
  transition: transform 0.25s ease;
  &:hover {
    transform: translateY(-2px);
  }
  &.active {
    color: #60a5fa !important;
    font-weight: 700;
  }
`;

/* Restore original positions */
const CONNECT = styled(NavLinkStyled)`
  position: absolute;
  top: 50%;
  right: -1.3rem;
  transform: rotate(90deg);
  ${navPill}
`;
