const WORK = styled(NavLinkStyled)`
  position: absolute;
  top: 50%;
  left: -0.8rem;
  transform: rotate(-90deg);
  ${navPill}
`;
const Certification = styled(NavLinkStyled)`
  position: absolute;
  top: 2rem;
  right: calc(1rem + 2vw);
  ${navPill}
`;
const BottomBar = styled.div`
  position: absolute;
  bottom: 2rem;
  left: 0;
  right: 0;
  width: 100%;
  display: flex;
  justify-content: space-evenly;
  z-index: 2;
`;
const ABOUT = styled(NavLinkStyled)`
  ${navPill}
`;
const SKILLS = styled(NavLinkStyled)`
  ${navPill}
`;
const useParticles = (count = 60) => {
  const canvasRef = useRef();
  const particles = useRef([]);
  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext("2d");
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;
    const colors = ["#60A5FA", "#1E40AF", "#93C5FD", "#3B82F6"];
    for (let i = 0; i < count; i++) {
      particles.current.push({
        x: Math.random() * canvas.width,
        y: Math.random() * canvas.height,
        r: Math.random() * 2 + 0.5,
        dx: (Math.random() - 0.5) * 0.5,
        dy: Math.random() * 1 + 0.3,
        color: colors[Math.floor(Math.random() * colors.length)],
        alpha: Math.random() * 0.7 + 0.3,
        dAlpha: Math.random() * 0.02,
      });
    }
    const animate = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      particles.current.forEach((p) => {
        p.y -= p.dy;
        p.x += p.dx;
        p.alpha += p.dAlpha;
        if (p.alpha > 1 || p.alpha < 0.3) p.dAlpha *= -1;
        if (p.y < -10) p.y = canvas.height + 10;
        if (p.x < -10) p.x = canvas.width + 10;
        if (p.x > canvas.width + 10) p.x = -10;
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.r, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(${parseInt(p.color.slice(1, 3), 16)},${parseInt(p.color.slice(3, 5), 16)},${parseInt(p.color.slice(5, 7), 16)},${p.alpha})`;
        ctx.shadowBlur = 10;
        ctx.shadowColor = p.color;
        ctx.fill();
      });
      requestAnimationFrame(animate);
    };
    animate();
    const handleResize = () => {
      canvas.width = window.innerWidth;
      canvas.height = window.innerHeight;
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, [count]);
  return canvasRef;
};

const Main = () => {
  const [click, setClick] = useState(false);
  const canvasRef = useParticles(60);

  const animationConfig = {
    nav: {
      initial: { y: -200 },
      animate: { y: 0 },
      transition: { type: "spring", duration: 1, delay: 0.5 },
    },
    bottom: {
      initial: { y: 200 },
      animate: { y: 0 },
      transition: { type: "spring", duration: 1, delay: 0.5 },
    },
  };

  return (
    <MainContainer>
      <ParticlesCanvas ref={canvasRef} />
      <Container>
        <LogoComponent theme={click ? "dark" : "light"} />
        <SocialIcons theme="dark" />
        <Center click={click} onClick={() => setClick(!click)}>
          <div className="dragon-container">
            <img src={Dragon || "/placeholder.svg"} alt="Dragon" />
          </div>
          <span>click</span>
        </Center>

        {/* Buttons at previous positions */}
        <Certification to="/certification">
          <motion.div
            {...animationConfig.nav}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.93 }}
          >
            <p className="nav-text">Certified</p>
          </motion.div>
        </Certification>

        <CONNECT to="/connect">
          <motion.div
            {...animationConfig.nav}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.93 }}
          >
            <p className="nav-text">Connect</p>
          </motion.div>
        </CONNECT>

        <WORK to="/work">
          <motion.div
            {...animationConfig.nav}
            whileHover={{ scale: 1.08 }}
            whileTap={{ scale: 0.93 }}
          >
            <p className="nav-text">Work</p>
          </motion.div>
        </WORK>

        <BottomBar>
          <ABOUT to="/about">
            <motion.div
              {...animationConfig.bottom}
              whileHover={{ scale: 1.08 }}
              whileTap={{ scale: 0.93 }}
            >
              <p className="nav-text">About</p>
            </motion.div>
          </ABOUT>
          <SKILLS to="/skills">
            <motion.div
              {...animationConfig.bottom}
              whileHover={{ scale: 1.08 }}
              whileTap={{ scale: 0.93 }}
            >
              <p className="nav-text">My Skills</p>
            </motion.div>
          </SKILLS>
        </BottomBar>
      </Container>
      {click && <Intro click={click} />}
    </MainContainer>
  );
};

export default Main;
